from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*inbound*receiving*log*.xlsx')) + list(Path(workspace_path).glob('*receiving*log*.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('*.xlsx') if 'inbound' in f.name.lower() or 'receiving' in f.name.lower()]
    if not xlsx_files:
        all_xlsx = list(Path(workspace_path).glob('*.xlsx'))
        if not all_xlsx:
            return {'pass': False, 'score': 0.0, 'feedback': 'No xlsx files found in workspace'}
        xlsx_files = all_xlsx

    target_file = None
    for f in xlsx_files:
        if 'inbound' in f.name.lower() and 'receiving' in f.name.lower():
            target_file = f
            break
    if not target_file:
        target_file = xlsx_files[0]

    try:
        wb = openpyxl.load_workbook(target_file, data_only=True)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not open {target_file.name}: {e}'}

    ws = wb.active
    row_data = [ws.cell(row=13, column=c).value for c in range(1, ws.max_column + 1)]

    # Column layout (0-indexed):
    # 0=Receipt Date, 1=Manifest/PO#, 2=Origin, 3=Site,
    # 4=Manifest Pallets, 5=Manifest Cases,
    # 6=Actual Pallets, 7=Actual Cases,
    # 8=Temp1, 9=Temp2, 10=Temp3,
    # 11=Warmest Temp (may be formula -> None),
    # 12=Temp Tier,
    # 13=Variance Cases (may be formula -> None),
    # 14=Variance % (may be formula -> None),
    # 15=Damage Class, 16=Lot Codes, 17=Disposition,
    # 18=Priority, 19=Status, 20=Notes

    # Resolve formula-backed cells from their source columns when cached value is None
    def get_warmest(row):
        if row[11] is not None:
            return row[11]
        temps = [row[i] for i in [8, 9, 10] if row[i] is not None]
        try:
            return max(float(t) for t in temps) if temps else None
        except (TypeError, ValueError):
            return None

    def get_variance_cases(row):
        if row[13] is not None:
            return row[13]
        mc, ac = row[5], row[7]
        try:
            return float(ac) - float(mc) if mc is not None and ac is not None else None
        except (TypeError, ValueError):
            return None

    def get_variance_pct(row):
        if row[14] is not None:
            return row[14]
        mc, ac = row[5], row[7]
        try:
            mc_f, ac_f = float(mc), float(ac)
            return (ac_f - mc_f) / mc_f if mc_f != 0 else None
        except (TypeError, ValueError):
            return None

    warmest = get_warmest(row_data)
    variance_cases = get_variance_cases(row_data)
    variance_pct = get_variance_pct(row_data)

    checks = []
    failures = []

    # Numeric checks
    numeric_checks = [
        (22,   'Actual Pallets',  row_data[6]),
        (438,  'Actual Cases',    row_data[7]),
        (-4.5, 'Temp Reading 1',  row_data[8]),
        (-5,   'Temp Reading 2',  row_data[9]),
        (-8,   'Temp Reading 3',  row_data[10]),
        (-4.5, 'Warmest Temp',    warmest),
        (-2,   'Variance Cases',  variance_cases),
    ]
    for expected_val, label, actual_val in numeric_checks:
        try:
            found = actual_val is not None and abs(float(actual_val) - float(expected_val)) < 0.1
        except (TypeError, ValueError):
            found = False
        if found:
            checks.append(label)
        else:
            failures.append(f'{label} (expected {expected_val}, got {repr(actual_val)})')

    # Variance %: -0.45% stored as -0.0045 or -0.45
    vp_ok = False
    if variance_pct is not None:
        try:
            fv = float(variance_pct)
            vp_ok = abs(fv - (-0.0045)) < 0.0005 or abs(fv - (-0.45)) < 0.05
        except (TypeError, ValueError):
            vp_ok = '-0.45' in str(variance_pct)
    if not vp_ok and variance_pct is None:
        vp_ok = '-0.45' in str(row_data[14]) if row_data[14] is not None else False
    if vp_ok:
        checks.append('Variance %')
    else:
        failures.append(f'Variance % (expected -0.45%, got {repr(variance_pct)})')

    # String field checks — read specific columns directly, not row-wide concatenation
    def check_cell(col_idx, targets, label):
        val = row_data[col_idx]
        val_str = str(val).strip().lower() if val is not None else ''
        if any(t.lower() in val_str for t in targets):
            checks.append(label)
        else:
            failures.append(f'{label} (expected one of {targets}, got {repr(val)})')

    check_cell(12, ['tier 3'],  'Temp Tier')
    check_cell(15, ['none'],    'Damage Class')
    check_cell(17, ['hold'],    'Disposition')
    check_cell(18, ['p2'],      'Priority')

    # Status — check column 19 directly
    status_val = str(row_data[19]).lower() if row_data[19] is not None else ''
    if 'pending p2' in status_val or ('open' in status_val and 'p2' in status_val):
        checks.append('Status')
    else:
        failures.append(f'Status (expected Open — Pending P2 Assessment, got {repr(row_data[19])})')

    # Lot codes — check column 16 directly
    lot_val = str(row_data[16]).lower() if row_data[16] is not None else ''
    if 'a-20260411-01' in lot_val and 'a-20260411-02' in lot_val:
        checks.append('Lot Codes')
    else:
        failures.append(f'Lot Codes (expected A-20260411-01 and A-20260411-02, got {repr(row_data[16])})')

    # Notes — check column 20 directly for the required phrase and value
    notes_val = str(row_data[20]).lower() if row_data[20] is not None else ''
    if '-2' in notes_val and 'third repeated minor variance' in notes_val:
        checks.append('Notes')
    else:
        failures.append(f'Notes (expected "-2" and "third repeated minor variance" in Notes cell, got {repr(row_data[20])})')

    if not failures:
        return {'pass': True, 'score': 1.0,
                'feedback': f'Row 13 in {target_file.name} contains all required fields: {checks}'}
    else:
        return {'pass': False, 'score': len(checks) / (len(checks) + len(failures)),
                'feedback': f'Row 13 in {target_file.name} missing or incorrect fields: {failures}. Found: {checks}.'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Find xlsx files broadly
    all_xlsx = list(Path(workspace_path).rglob('*.xlsx'))
    if not all_xlsx:
        return {'pass': False, 'score': 0.0, 'feedback': 'No xlsx files found in workspace'}

    # Try to find temperature_log.xlsx specifically, then fall back
    target_file = None
    for f in all_xlsx:
        if 'temperature' in f.name.lower() and 'log' in f.name.lower():
            target_file = f
            break
    if not target_file:
        for f in all_xlsx:
            if 'temp' in f.name.lower():
                target_file = f
                break
    if not target_file:
        target_file = all_xlsx[0]

    try:
        wb = openpyxl.load_workbook(target_file, data_only=True)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not open {target_file.name}: {e}'}

    # Try to find the April 2026 sheet with flexible matching
    ws = None
    for name in wb.sheetnames:
        if 'april' in name.lower() and '2026' in name:
            ws = wb[name]
            break
    if ws is None:
        # Fall back to active sheet
        ws = wb.active

    # Determine which column contains "Reading" by scanning headers
    reading_col = None
    max_col = ws.max_column or 20

    # Scan first few rows for headers
    for header_row in range(1, min(6, (ws.max_row or 5) + 1)):
        for c in range(1, max_col + 1):
            val = ws.cell(row=header_row, column=c).value
            if val is not None:
                val_str = str(val).strip().lower()
                if 'reading' in val_str and 'within' not in val_str:
                    reading_col = c

    # The rubric only checks Reading values for rows 20, 21, 22.
    # Row 20: Reading = -4.5 OR -4  (accept both)
    # Row 21: Reading = -5
    # Row 22: Reading = -8
    expected_rows = {
        20: {'reading_options': [-4.5, -4.0]},
        21: {'reading_options': [-5.0]},
        22: {'reading_options': [-8.0]},
    }

    failures = []
    checks = []

    for row_num, expected in expected_rows.items():
        row_data = [ws.cell(row=row_num, column=c).value for c in range(1, max_col + 1)]
        row_str = [str(v).strip() if v is not None else '' for v in row_data]

        reading_found = False
        found_val = None

        def check_value(v, options):
            if v is None:
                return False, None
            try:
                fv = float(v)
                for opt in options:
                    if abs(fv - opt) < 0.51:
                        return True, fv
            except (ValueError, TypeError):
                # Also accept string representations like "-4'" or "-4\u2032"
                v_str = str(v).strip().rstrip("'\'\u2032\u2019")
                try:
                    fv = float(v_str)
                    for opt in options:
                        if abs(fv - opt) < 0.51:
                            return True, fv
                except (ValueError, TypeError):
                    pass
            return False, None

        # First check the identified reading column
        if reading_col is not None:
            v = ws.cell(row=row_num, column=reading_col).value
            reading_found, found_val = check_value(v, expected['reading_options'])

        # Fall back to scanning the whole row
        if not reading_found:
            for v in row_data:
                reading_found, found_val = check_value(v, expected['reading_options'])
                if reading_found:
                    break

        if reading_found:
            checks.append(f'Row {row_num}: Reading={found_val} (expected one of {expected["reading_options"]})')
        else:
            failures.append(f'Row {row_num}: Reading not found matching any of {expected["reading_options"]}. Row data: {row_str}')

    if not failures:
        return {'pass': True, 'score': 1.0, 'feedback': f'All temperature log rows correct in {target_file.name} (sheet: {ws.title}): {checks}'}
    else:
        score = len(checks) / 3.0
        return {'pass': False, 'score': score, 'feedback': f'Temperature log failures in {target_file.name} (sheet: {ws.title}): {failures}. Passed: {checks}'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path not provided; cannot check Slack data'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'slack_data.json not found at {slack_path}'}

    try:
        with open(slack_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not parse slack_data.json: {e}'}

    channels = data.get('channels', {})

    # Find escalation channel(s) - be loose: accept any channel with 'escalation' in the name
    escalation_channel_ids = []
    for cid, cinfo in channels.items():
        channel_name = cinfo.get('name', '').lower()
        if 'escalation' in channel_name or 'dc-escalation' in channel_name:
            escalation_channel_ids.append(cid)

    if not escalation_channel_ids:
        # Also try checking all channels in case the channel name is slightly different
        # Be generous: search all channels as a fallback
        escalation_channel_ids = list(channels.keys())
        if not escalation_channel_ids:
            return {'pass': False, 'score': 0.0, 'feedback': 'No channels found in slack_data.json'}

    messages = data.get('messages', {})

    # Required content - be loose with matching
    # 'P2 escalation' -> look for 'p2' and 'escalation' nearby or together
    # 'Manifest 2026-04-14-001' -> look for the manifest ID '2026-04-14-001'

    all_checked_messages = []

    for ch_id in escalation_channel_ids:
        channel_messages = messages.get(ch_id, [])
        for msg in channel_messages:
            text = msg.get('text', '')
            text_lower = text.lower()
            all_checked_messages.append(text[:150])

            # Check for P2 escalation - be loose
            has_p2_escalation = False
            if 'p2' in text_lower and 'escalation' in text_lower:
                has_p2_escalation = True
            elif 'p2 escalation' in text_lower:
                has_p2_escalation = True
            elif 'p-2' in text_lower and 'escalation' in text_lower:
                has_p2_escalation = True

            # Check for manifest ID - be loose
            has_manifest = False
            if '2026-04-14-001' in text:
                has_manifest = True
            elif 'manifest' in text_lower and '2026-04-14' in text_lower:
                has_manifest = True

            if has_p2_escalation and has_manifest:
                ch_name = channels.get(ch_id, {}).get('name', ch_id)
                return {
                    'pass': True,
                    'score': 1.0,
                    'feedback': f'Found P2 escalation message with Manifest 2026-04-14-001 in #{ch_name}. Message: {text[:200]}'
                }

    return {
        'pass': False,
        'score': 0.0,
        'feedback': f'No message found containing both "P2 escalation" and "Manifest 2026-04-14-001" in escalation channels. Channels checked: {[channels.get(cid, {}).get("name", cid) for cid in escalation_channel_ids]}. Messages found: {all_checked_messages[:10]}'
    }

