from pathlib import Path
import json
import re


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0,
                'feedback': 'external_services_path not provided; cannot check mailbox'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0,
                'feedback': f'mailbox.json not found at {mailbox_path}'}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not parse mailbox.json: {e}'}

    emails = data.get('emails', [])
    sent_emails = [e for e in emails if (e.get('folder', '') or '').lower() == 'sent']
    if not sent_emails:
        return {'pass': False, 'score': 0.0, 'feedback': 'No sent emails found in mailbox.json'}

    target_to = 'jacob.patel@prairiestar.com'

    # Normalize en-dash, em-dash, and hyphen all to plain hyphen for subject comparison
    def normalize_dashes(s):
        return re.sub(r'[\u2013\u2014\-]', '-', s)

    expected_subject_norm = normalize_dashes(
        'P3 - Inbound Waco Manifest 2026-04-14-001 - 2026-04-14'
    ).lower()

    required_body_terms = [
        '2026-04-14-001',
        '-4.5',
        '-5',
        '-8',
        'enhanced expiry monitoring',
        '-2',
        'repeated minor variance',
    ]
    explanation_equivalents = ['explanation', 'explain', 'rationale', 'reason', 'clarif', 'justif']

    def get_to_lower(email):
        to_addr = email.get('to_addr', '') or email.get('to', '') or ''
        if isinstance(to_addr, list):
            to_addr = ' '.join(to_addr)
        return to_addr.lower()

    diagnostics = []
    for email in sent_emails:
        to_lower = get_to_lower(email)
        if target_to not in to_lower:
            continue

        subject = email.get('subject', '') or ''
        subj_norm = normalize_dashes(subject).lower().strip()
        body = (email.get('body_text', '') or email.get('body', '') or '')
        body_lower = body.lower()

        subj_match = subj_norm == expected_subject_norm
        missing_body = [t for t in required_body_terms if t.lower() not in body_lower]
        has_expl = any(term in body_lower for term in explanation_equivalents)

        if subj_match and not missing_body and has_expl:
            return {'pass': True, 'score': 1.0,
                    'feedback': f'Found sent email to {target_to} with subject "{subject}" '
                                f'and all required body content.'}

        diagnostics.append(
            f'Email subject "{subject}": subject_match={subj_match}, '
            f'missing_body={missing_body}, has_explanation_term={has_expl}'
        )

    if not diagnostics:
        return {'pass': False, 'score': 0.0,
                'feedback': f'No sent emails found to {target_to}.'}
    return {'pass': False, 'score': 0.0,
            'feedback': 'No sent email to {} satisfied all checks. {}'.format(
                target_to, ' | '.join(diagnostics))}

