                    cell_str = str(cell_val).lower().strip()
                    for f_val in forbidden:
                        if f_val in cell_str:
                            violations.append(f'Sheet={ws.title}, Row={row_idx}, Value={cell_val}')

    if violations:
        return {'pass': False, 'score': 0.0,
                'feedback': f'Found forbidden lot codes in {target_file.name}: {violations}'}
    else:
        return {'pass': True, 'score': 1.0,
                'feedback': f'No rows with A-20260411-01 or A-20260411-02 found in {target_file.name} — correct'}

from pathlib import Path
import json


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0,
                'feedback': 'external_services_path not provided; cannot check mailbox'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0,
                'feedback': f'mailbox.json not found at {mailbox_path}'}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not parse mailbox.json: {e}'}

    emails = data.get('emails', [])
    sent_emails = [e for e in emails if (e.get('folder', '') or '').lower() == 'sent']

    target_to = 'jacob.patel@prairiestar.com'

    def get_to_lower(email):
        to_addr = email.get('to_addr', '') or email.get('to', '') or ''
        if isinstance(to_addr, list):
            to_addr = ' '.join(to_addr)
        return to_addr.lower()

    matches = []
    for email in sent_emails:
        subject = email.get('subject', '') or ''
        to_lower = get_to_lower(email)
        if 'p3' in subject.lower() and target_to in to_lower:
            matches.append(email.get('email_id') or subject)

    if len(matches) == 1:
        return {'pass': True, 'score': 1.0,
                'feedback': f'Exactly one P3 email sent to {target_to} (matched: {matches[0]}).'}
    return {'pass': False, 'score': 0.0,
            'feedback': f'Expected exactly 1 P3 email sent to {target_to}, found {len(matches)}. '
                        f'Matches: {matches}'}
